  int k = k1 + blockIdx.x * blockDim.x + threadIdx.x;
  if (k < k2) {
    float distance = dist_device(d_points[i].coord, d_points[k].coord, dim);
    if (d_points[k].cost > distance * d_points[k].weight) {
      d_points[k].cost = distance * d_points[k].weight;
      d_points[k].assign = i;
    }
  }
}

float pspeedy(Points *points, float z, long *kcenter, int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE
  double t1 = gettime();
#endif

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

  static double totalcost;

  static bool open = false;
  static double* costs; 
  static int i;

#ifdef ENABLE_THREADS
  static pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;
  static pthread_cond_t cond = PTHREAD_COND_INITIALIZER;
#endif

#ifdef PRINTINFO
  if( pid == 0 ){
    fprintf(stderr, "Speedy: facility cost %lf\n", z);
  }
#endif

  // Allocate device memory for points and coords
  Point* d_points;
  float* d_coords;
  size_t points_size = points->num * sizeof(Point);
  size_t coords_size = points->num * points->dim * sizeof(float);

  cudaMalloc(&d_points, points_size);
  cudaMalloc(&d_coords, coords_size);

  // Copy coords to device
  cudaMemcpy(d_coords, block, coords_size, cudaMemcpyHostToDevice);

  // Prepare host copy of points with device coord pointers
  Point* h_points = points->p;
  Point* h_points_copy = (Point*)malloc(points_size);
  for (int idx = 0; idx < points->num; idx++) {
    h_points_copy[idx] = h_points[idx];
    h_points_copy[idx].coord = d_coords + idx * points->dim;
  }
  cudaMemcpy(d_points, h_points_copy, points_size, cudaMemcpyHostToDevice);
  free(h_points_copy);

  // Initialize costs on device
  int threadsPerBlock = 256;
  int blocksPerGrid = (k2 - k1 + threadsPerBlock - 1) / threadsPerBlock;
  pspeedy_init_costs<<<blocksPerGrid, threadsPerBlock>>>(d_points, points->dim, k1, k2);
  cudaDeviceSynchronize();

  if( pid==0 )   {
    *kcenter = 1;
    costs = (double*)malloc(sizeof(double)*nproc);
  }

  if( 0 != pid ) { 
    while(1) {
#ifdef ENABLE_THREADS
      pthread_mutex_lock(&mutex);
      while(!open) pthread_cond_wait(&cond,&mutex);
      pthread_mutex_unlock(&mutex);
#endif
      if( i >= points->num ) break;
      blocksPerGrid = (k2 - k1 + threadsPerBlock - 1) / threadsPerBlock;
      pspeedy_update_costs<<<blocksPerGrid, threadsPerBlock>>>(d_points, points->dim, k1, k2, i);
      cudaDeviceSynchronize();
#ifdef ENABLE_THREADS
      pthread_barrier_wait(barrier);
      pthread_barrier_wait(barrier);
#endif
    } 
  }
  else  { 
    for(i = 1; points->num > i; i++ )  {
      bool to_open = ((float)lrand48()/(float)INT_MAX)<(points->p[i].cost/z);
      if( to_open )  {
	(*kcenter)++;
#ifdef ENABLE_THREADS
	pthread_mutex_lock(&mutex);
#endif
	open = true;
#ifdef ENABLE_THREADS
	pthread_mutex_unlock(&mutex);
	pthread_cond_broadcast(&cond);
#endif
	blocksPerGrid = (k2 - k1 + threadsPerBlock - 1) / threadsPerBlock;
	pspeedy_update_costs<<<blocksPerGrid, threadsPerBlock>>>(d_points, points->dim, k1, k2, i);
	cudaDeviceSynchronize();
#ifdef ENABLE_THREADS
	pthread_barrier_wait(barrier);
#endif
	open = false;
#ifdef ENABLE_THREADS
	pthread_barrier_wait(barrier);
#endif
      }
    }
#ifdef ENABLE_THREADS
    pthread_mutex_lock(&mutex);
#endif
    open = true;
#ifdef ENABLE_THREADS
    pthread_mutex_unlock(&mutex);
    pthread_cond_broadcast(&cond);
#endif
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  open = false;

  // Copy back costs and assigns
  cudaMemcpy(points->p, d_points, points_size, cudaMemcpyDeviceToHost);

  double mytotal = 0;
  for( int k = k1; k2 > k; k++ )  {
    mytotal += points->p[k].cost;
  }
  costs[pid] = mytotal;
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if( pid == 0 )
    {
      totalcost=z*(*kcenter);
      for( int i = 0; i < nproc; i++ )
	{
	  totalcost = totalcost + (costs[i]);
	} 
      free(costs);
    }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

#ifdef PRINTINFO
  if( pid == 0 )
    {
      fprintf(stderr, "Speedy opened %d facilities for total cost %lf\n",
	      *kcenter, totalcost);
      fprintf(stderr, "Distance Cost %lf\n", totalcost - z*(*kcenter));
    }
#endif

#ifdef PROFILE
  double t2 = gettime();
  if( 0 == pid ) {
    time_speedy = time_speedy + (t2 -t1);
  }
#endif

  cudaFree(d_coords);
  cudaFree(d_points);

  return(totalcost);
}

