#include <stdio.h>
#include <iostream>
#include <fstream>
#include <stdlib.h>
#include <sys/time.h>
#include <string.h>
#include <assert.h>
#include <math.h>
#include <sys/resource.h>
#include <limits.h>
#include <cuda_runtime.h>

#ifdef ENABLE_PARSEC_HOOKS
#include <hooks.h>
#endif

using namespace std;

#define MAXNAMESIZE 1024 
#define SEED 1

#define SP 1 

#define ITER 3 

#define PROFILE 

#define CACHE_LINE 512 

typedef struct {
  float weight;
  float *coord;
  long assign;  
  float cost;  
} Point;

typedef struct {
  long num; 
  int dim;  
  Point *p; 
} Points;

static bool *switch_membership; 
static bool* is_center; 
static int* center_table; 

static int nproc; 

#ifdef PROFILE
double time_local_search;
double time_speedy;
double time_select_feasible;
double time_gain;
double time_shuffle;
double time_gain_dist;
double time_gain_init;
#endif 

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return (double)t.tv_sec+t.tv_usec*1e-6;
}

__device__ float dist_device(const float* p1_coord, const float* p2_coord, int dim)
{
  float result=0.0f;
  for (int i=0; i<dim; i++)
    result += (p1_coord[i] - p2_coord[i])*(p1_coord[i] - p2_coord[i]);
  return result;
}

__global__ void pgain_kernel(Point* d_points, int dim, int k1, int k2, int x, bool* d_switch_membership, bool* d_is_center, int* d_center_table, double* d_work_mem, int stride, int nproc, double z)
{
  int i = k1 + blockIdx.x * blockDim.x + threadIdx.x;
  if (i >= k2) return;

  float x_cost = dist_device(d_points[i].coord, d_points[x].coord, dim) * d_points[i].weight;
  float current_cost = d_points[i].cost;

  if (x_cost < current_cost) {
    d_switch_membership[i] = true;
    atomicAdd(&d_work_mem[blockIdx.x * stride + stride - 1], x_cost - current_cost);
  } else {
    int assign = d_points[i].assign;
    atomicAdd(&d_work_mem[blockIdx.x * stride + d_center_table[assign]], current_cost - x_cost);
  }
}

double pgain(long x, Points *points, double z, long int *numcenters, int pid, pthread_barrier_t* barrier)
{
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
#ifdef PROFILE
  double t0 = gettime();
#endif	

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

  int number_of_centers_to_close = 0;

  static double *work_mem;
  static double gl_cost_of_opening_x;
  static int gl_number_of_centers_to_close;

  int stride = *numcenters+2;
  int cl = CACHE_LINE/sizeof(double);
  if( stride % cl != 0 ) { 
    stride = cl * ( stride / cl + 1);
  }
  int K = stride -2 ; 

  double cost_of_opening_x = 0;

  if( 0 == pid ) { 
    work_mem = (double*) malloc(stride*(nproc+1)*sizeof(double));
    gl_cost_of_opening_x = 0;
    gl_number_of_centers_to_close = 0;
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  int count = 0;
  for( int i = k1; i < k2; i++ ) {
    if( is_center[i] ) {
      center_table[i] = count++;
    }
  }
  work_mem[pid*stride] = count;

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if( pid == 0 ) {
    int accum = 0;
    for( int p = 0; p < nproc; p++ ) {
      int tmp = (int)work_mem[p*stride];
      work_mem[p*stride] = accum;
      accum += tmp;
    }
  }

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  for( int i = k1; i < k2; i++ ) {
    if( is_center[i] ) {
      center_table[i] += (int)work_mem[pid*stride];
    }
  }

  memset(switch_membership + k1, 0, (k2-k1)*sizeof(bool));
  memset(work_mem+pid*stride, 0, stride*sizeof(double));
  if( pid== 0 ) memset(work_mem+nproc*stride,0,stride*sizeof(double));

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
#ifdef PROFILE
  double t1 = gettime();
  if( pid == 0 ) time_gain_init += t1-t0;
#endif

  double* lower = &work_mem[pid*stride];
  double* gl_lower = &work_mem[nproc*stride];

  // Copy data to device
  Point* d_points;
  bool* d_switch_membership;
  bool* d_is_center;
  int* d_center_table;
  double* d_work_mem;

  cudaMalloc(&d_points, points->num * sizeof(Point));
  cudaMalloc(&d_switch_membership, points->num * sizeof(bool));
  cudaMalloc(&d_is_center, points->num * sizeof(bool));
  cudaMalloc(&d_center_table, points->num * sizeof(int));
  cudaMalloc(&d_work_mem, stride * (nproc + 1) * sizeof(double));

  cudaMemcpy(d_points, points->p, points->num * sizeof(Point), cudaMemcpyHostToDevice);
  cudaMemcpy(d_switch_membership, switch_membership, points->num * sizeof(bool), cudaMemcpyHostToDevice);
  cudaMemcpy(d_is_center, is_center, points->num * sizeof(bool), cudaMemcpyHostToDevice);
  cudaMemcpy(d_center_table, center_table, points->num * sizeof(int), cudaMemcpyHostToDevice);
  cudaMemcpy(d_work_mem, work_mem, stride * (nproc + 1) * sizeof(double), cudaMemcpyHostToDevice);

  int threadsPerBlock = 256;
  int blocksPerGrid = (k2 - k1 + threadsPerBlock - 1) / threadsPerBlock;

  pgain_kernel<<<blocksPerGrid, threadsPerBlock>>>(d_points, points->dim, k1, k2, (int)x, d_switch_membership, d_is_center, d_center_table, d_work_mem, stride, nproc, z);
  cudaDeviceSynchronize();

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif	
#ifdef PROFILE
  double t2 = gettime();
  if( pid==0){
    time_gain_dist += t2 - t1;
  }
#endif	

  // Copy back work_mem for reduction
  cudaMemcpy(work_mem, d_work_mem, stride * (nproc + 1) * sizeof(double), cudaMemcpyDeviceToHost);

  for ( int i = k1; i < k2; i++ ) {
    if( is_center[i] ) {
      double low = z;
      for( int p = 0; p < nproc; p++ ) {
	low += work_mem[center_table[i]+p*stride];
      }
      gl_lower[center_table[i]] = low;
      if ( low > 0 ) {
	++number_of_centers_to_close;  
	cost_of_opening_x -= low;
      }
    }
  }

  work_mem[pid*stride + K] = number_of_centers_to_close;
  work_mem[pid*stride + K+1] = cost_of_opening_x;

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if( pid==0 ) {
    gl_cost_of_opening_x = z;
    for( int p = 0; p < nproc; p++ ) {
      gl_number_of_centers_to_close += (int)work_mem[p*stride + K];
      gl_cost_of_opening_x += work_mem[p*stride+K+1];
    }
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if ( gl_cost_of_opening_x < 0 ) {
    for ( int i = k1; i < k2; i++ ) {
      bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
      if ( switch_membership[i] || close_center ) {
	points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
	points->p[i].assign = x;
      }
    }
    for( int i = k1; i < k2; i++ ) {
      if( is_center[i] && gl_lower[center_table[i]] > 0 ) {
	is_center[i] = false;
      }
    }
    if( x >= k1 && x < k2 ) {
      is_center[x] = true;
    }
    if( pid==0 ) {
      *numcenters = *numcenters + 1 - gl_number_of_centers_to_close;
    }
  }
  else {
    if( pid==0 )
      gl_cost_of_opening_x = 0;  
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  if( pid == 0 ) {
    free(work_mem);
  }

  cudaFree(d_points);
  cudaFree(d_switch_membership);
  cudaFree(d_is_center);
  cudaFree(d_center_table);
  cudaFree(d_work_mem);

#ifdef PROFILE
  double t3 = gettime();
  if( pid==0 )
  time_gain += t3-t0;
#endif

  return -gl_cost_of_opening_x;
}
